// Node.js example: simple promise pool (bulkhead) using p-limit
const pLimit = require('p-limit');
const limit = pLimit(5); // allow 5 concurrent jobs for a heavy route

async function handleHeavyRequest(req, res) {
  try {
    const result = await limit(() => heavyWork(req.body));
    res.json(result);
  } catch (e) {
    // If queue is overloaded p-limit will simply queue, so consider adding a hard cap
    res.status(503).send('Service busy');
  }
}

